Cypress.on('window:before:load', (win) => {
  consoleError = cy.spy(win.console, 'error').log(false);
  consoleWarning = cy.spy(win.console, 'warn').log(false);
  consoleLog = cy.spy(win.console, 'log').log(false);
});
const DELAY = 1000;


describe('Basic Tests', () => {
  beforeEach(() => {
    // Cypress starts out with a blank slate for each test
    // so we must tell it to visit our website with the `cy.visit()` command.
    // Since we want to visit the same URL at the start of all our tests,
    // we include it in our beforeEach function so that it runs before each test.
    cy.visit(`http://localhost:${Cypress.env('theport') || 8080}`).log(false)
  })
  it('passes a very basic test to confirm tests are running', () => {
    cy.get('h1').should('include.text', 'Problem Set 2')
  })

  describe('problem 1', () => {
      const clCount = [0,1,2,3,4,5,6];
      const offset = clCount.length - 1;
      clCount.forEach((count) => {
        it (`Click "Move Items" ${count} times. Expect ${offset - count } on the left,  ${count} on the right`, () => {
          for (let i= 0; i < count; i++) {
            cy.get('#move-the-items').click();
          }

          cy.get('#start-list li').should($el => {
            expect($el, `Clicked "Move Items" ${count} times. Should be ${offset - count} items on the left, but there were ${$el.length}`).to.have.length(offset - count)
          });
          cy.get('#end-list li').should($el => {
            expect($el, `Clicked "Move Items" ${count} times. Should be ${count} items on the right, but there were ${$el.length}`).to.have.length(count)
          });
          cy.get('#move-the-items').click();
        });
      })
    it('Click more than 6 times', () => {
      for (let i= 0; i < 7; i++) {
        cy.get('#move-the-items').click();
      }
      cy.get('#end-list').invoke('prop', 'childNodes').should($childNodes => {
        const nullNodes = Array.from($childNodes).filter(node =>
            node.nodeType === 3 && node.nodeValue.trim() === 'null'
        );
        expect(nullNodes.length, `With no items on the left, clicking shouldn't add anything more on the right`).to.equal(0);
      });
    })
  });

  describe('problem 2', () => {
    it('is a skipped problem', () => {
      cy.get(true).should(() => {
        expect(true, 'This is a skipped problem. There is nothing to test.').to.equal(true)
      });
    })
  })

  describe('Problem 3', () => {
    it('starts with five boxes', () => {
      cy.get('.boxes').find('.box').should($els => {
        expect($els, 'When the page loads there should be five boxes').to.have.length(5)
      })
    })

    describe('hovering over each item changes the class and removes it after 250 ms', () => {
      const boxes  = [1,5,3,4,2];
      boxes.forEach(box => {
        it(`hover over box ${box}, it should turn red then vanish`, () => {
          cy.clock()
          cy.get(`[data-box="${box}"]`).should($el => {
            expect($el, `[data-box="${box}"] should not have the 'red' class when the page first loads`).to.not.have.class('red')
          })
          cy.get(`[data-box="${box}"]`).trigger('mouseenter').should($el => {
            expect($el, `[data-box="${box}"] should have the 'red' class when the pointer is over it`).to.have.class('red')
          })

          cy.get(`[data-box="${box}"]`).trigger('mouseleave').should($el => {
            expect($el, `[data-box="${box}"] should not have the 'red' class when the pointer leaves it`).to.not.have.class('red')
          })
          cy.tick(250);
          cy.log('Fast forward 250 ms after the mouse leaves')
          cy.get(`[data-box="${box}"]`).should('not.exist')
        })
      })
    });
  })

  describe('problem 4', () => {
    it ('rotator starts without style attribute', () => {
      cy.get('#rotator').should('not.have.attr', 'style');
    })
   const angles = [5,68,160,220];
    angles.forEach((angle) => {
      it(`Set value of #rotator to ${angle}, and it should rotate ${angle} degrees`, () => {
        cy.get('#change-angle').type(angle).trigger('input')
        cy.get('#rotator').should($el => {
          expect($el.attr('style'), `Set the angle value to ${angle}, and the 'style' attribute should include 'rotate(${angle}deg)'`).to.include(`rotate(${angle}deg)`)
        })
      })
    })
  })

  describe('problem 5', () => {
    it('identified the (fake) event type', () => {
      cy.get('html').should($el => {
        const u = $el.find('#uniq').text();
        const evl = $el.find('#p5-code').text();
        const hg = $el.find('#p5-hug').text();
        expect(evl, ` the value of TypeOfEventIsProblem5ListeningTo is not correct. You provided ${evl} If it ends with '-event' remove that part`).to.equal(oa(u));
        expect(hg, `The value of whatShouldTheEventHug is not correct, it is a different thing to hug`).to.include('rescue dog');
      })
    })
  });


  afterEach(() => {
    // Confirm there are no console log/warning/errors after every test iteration.
    cy.wait(DELAY).then(() => {
      if (consoleLog.callCount > 0) {
        throw new Error('YOU SHOULD NOT HAVE console.log() IN YOUR SUBMITTED CODE'.repeat(20))
      }
      if (consoleError.callCount > 0) {
        throw new Error('ERRORS FOUND IN YOUR CODE! You need to fix them. Check the JS console in your application. '.repeat(20))
      }
      if (consoleWarning.callCount > 0) {
        throw new Error('WARNINGS FOUND IN YOUR CODE! You need to address them. Check the JS console in your application.'.repeat(20))
      }
    });
  });
})
